if @invoiceCode = 'HDA' select @tableName = 'm81$'+ convert(char(6), (select ngay_ct from c81$000000 where stt_rec = @invoiceID), 112)
  else if @invoiceCode = 'HD1' select @tableName = 'm21$'+ convert(char(6), (select ngay_ct from c21$000000 where stt_rec = @invoiceID), 112)
  else if @invoiceCode = 'HD2' select @tableName = 'm22$'+ convert(char(6), (select ngay_ct from c22$000000 where stt_rec = @invoiceID), 112)
  else if @invoiceCode = 'HD4' select @tableName = 'm25$'+ convert(char(6), (select ngay_ct from c25$000000 where stt_rec = @invoiceID), 112)
  else if @invoiceCode = 'HD5' select @tableName = 'hddc'
  else if @invoiceCode = 'PXC' select @tableName = 'm86$'+ convert(char(6), (select ngay_ct from c86$000000 where stt_rec = @invoiceID), 112)
  else if @invoiceCode = 'PXD' select @tableName = 'm26$000000'
  else if @invoiceCode = 'HD6' select @tableName = 'm42$000000'

