  select @s = @s + char(13) + 'select so_ct, so_seri, ngay_ct, ma_kh from ' + rtrim(@tableName) + ' where stt_rec = ''' + replace(@invoiceID, '''', '') + ''''
  exec sp_executesql @s
end
select @invoiceNumber = so_ct, @invoiceSerial = so_seri, @invoiceDate = ngay_ct, @invoiceCustomer = ma_kh from #t
drop table #t
select @invoiceNumber = isnull(@invoiceNumber, ''), @invoiceSerial = isnull(@invoiceSerial, ''), @invoiceCustomer = isnull(@invoiceCustomer, '')

