script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', null, null, 'status');&InitFormDetailTaxEdit;}
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  onChange$Voucher$TypeList(f.getItem('loai_bk'), false);
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&LoadFormDetailTax;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;
  &VoucherLogHandleStatus;
  set$Voucher$DefaultValue(f);
}
function close$Voucher$(f) {
  &ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('ddc')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
    &CancelStatusExplore;
    &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

&ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
  &ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('ddc')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: null, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt,t_ck_nt:t_tien2,t_thue,t_tt,t_ck');

    var $dt = {};
    $dt.aGridFields = 'gia_nt,tien_nt2,ck_nt:gia,tien2,ck';
    $dt.aTotalFields = [['t_tien_nt2', 'tien_nt2'],['t_tien2', 'tien2'],['t_ck_nt', 'ck_nt'], ['t_ck', 'ck']];
    &DetailTaxCurrencyCreate;
    v.addGridFields(g, $dt.aGridFields);
    v.addTotalFields(g, $dt.aTotalFields);
    v.set_referenceFields(null);
    v.set_executeExpression($dt.aExpression);

  &CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      var a = [['ddc', 'ma_tt'], ['dinv', 'ma_tt']];
      focus$Voucher$Tab(f, a);
      &PostCurrencySelected;
    }
  }
}


function onChange$Voucher$Tab(sender, e) {
  var a = ['ddc', 'dinv'];
  focus$Voucher$Tab(sender.parentForm, a);
  &PostTabFocus;
}
function focus$Voucher$Tab(f, a) {
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;
  &PostTabChange;
  Array.add(a, 'loai_bk');
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$TaxCode(o) {
  var f = o.parentForm;
  if ($func.trim(f.getItemValue('ma_thue'))) o.parentForm.request('GetTaxRate', 'GetTaxRate', ['ma_thue'], o);
  else if (f.getItemValue('thue_suat')) {
    f.setItemValue('thue_suat', 0);
    f.executeExpression(['[t_thue_nt]:=([t_tien_nt2] - [t_ck_nt])*[thue_suat]/100', '[t_thue]:=([t_tien2] - [t_ck])*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
  }
}

function onChange$VoucherValue(o) {
  var f = o.parentForm, c = o.field.Name;
  switch (c) {
    case 't_tien_nt2':
      f.executeExpression(['[t_tien2]:=[t_tien_nt2]*[ty_gia]', '[t_thue_nt]:=([t_tien_nt2] - [t_ck_nt])*[thue_suat]/100', '[t_thue]:=([t_tien2] - [t_ck])*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      break;
    case 't_tien2':
      f.executeExpression(['[t_thue]:=([t_tien2] - [t_ck])*[thue_suat]/100', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      break;
    case 't_thue_nt':
      f.executeExpression(['[t_thue]:=[t_thue_nt]*[ty_gia]', '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      f.live(f.getItem('t_thue'));
      break;
    case 't_thue':
      f.executeExpression(['[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      break;
    case 't_ck_nt':
      f.executeExpression(['[t_ck]:=[t_ck_nt]*[ty_gia]', '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      break;
    case 't_ck':
      f.executeExpression(['[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      break;
    case 't_tt_nt':
      f.executeExpression(['[t_tt]:=[t_tt_nt]*[ty_gia]']);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      set$Voucher$DefaultValue(f);
      break;
    &VoucherNumberReading;
      &CurrencyResponse;
    case 'Customer':
      f.setItemControlBehavior('ten_khthue', result[0].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[1].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[2].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[3].Value, null, &ResetCustInfoFields;);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'GetTaxRate':
      var r = result[0].Value;
      if (f.getItemValue('thue_suat') != r) {
        f.setItemValue('thue_suat', r);
        f.executeExpression(['[t_thue_nt]:=([t_tien_nt2] - [t_ck_nt])*[thue_suat]/100', '[t_thue]:=([t_tien2] - [t_ck])*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
      }
      f.setItemControlBehavior('tk_thue_co', result[1].Value, '', true);
      break;
    &EIResponseCompleteChecking;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
function set$Voucher$DefaultValue(f) {
  &DetailTaxFormDefaultValue;
}
function onChange$Voucher$TypeList(o, d) {
  var f = o.parentForm, v = (o.value == '2'), c = 'mau_bc,ma_tc';
  if (!v) {
    f.setItemControlBehavior('mau_bc', '', '', false);
    f.setItemControlBehavior('ma_tc', '', '', false);
  }
  else {if(d) f.getItem('mau_bc').value = '&DefaultReportForm;';}

  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem(a[i]);
      $common.setVisible(o.a, v);
      o.field.AllowNulls = !v;
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
      f.getItem(a[i]).disabled = !v;
    }
  }
}
/* <flatten type="Javascript"> */
function onChange$Voucher$VoucherDate(o) {o.parentForm.getItem('ngay_ct').value = o.parentForm.getItem('ngay_lct').value;}
/* </flatten> */
